import android.content.Context
import android.content.SharedPreferences

class AuthManager(private val context: Context) {

    private lateinit var prefs: SharedPreferences
    private val PREFS_NAME = "auth_manager"
    private val PREF_TOKEN_KEY = "token"
    private val PREF_ID_KEY = "id"

    init {
        prefs = context.getSharedPreferences(PREFS_NAME, 0)
    }

    fun saveAuthToken(token: String) {
        prefs.edit().putString(PREF_TOKEN_KEY, token).apply()
    }

    fun saveUserId(id: String) {
        prefs.edit().putString(PREF_ID_KEY, id).apply()
    }

    fun getAuthToken(): String? {
        return prefs.getString(PREF_TOKEN_KEY, null)
    }

    fun getUserID(): String? {
        return prefs.getString(PREF_ID_KEY, null)
    }

    fun isLoggedIn(): Boolean {
        val token = getAuthToken()
        val userId = getUserID()
        return !token.isNullOrBlank() && !userId.isNullOrBlank()
    }
}